sql:
SELECT SUM(data_used) AS total_data_used
FROM user_activity
WHERE user_id = 0;

SELECT SUM(data_used) AS total_data_used
FROM user_activity
WHERE user_id = 0 AND activity_date = '0';

SELECT SUM(volume) AS total_volume
FROM stock_data
WHERE company_id = 1 AND date = '1';

external_knowledge:
- 'Best performing stocks' refers to the ones with the highest adjusted closing price; 
- 'Pro users' are those with a subscription level of 'pro'; 
- 'Activity count' refers to the number of activities performed by a user; 
- 'Top 5' refers to the top 5 ranked stocks based on the adjusted closing price.

- 'Active' in this context refers to users with higher activity counts in the `user_activity` table over the last 30 days;
- 'Professional users' are those with a subscription level of 'pro';
- 'Top companies' are determined by their average trading volume over the last 30 days.

